# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_mail import Mail, Message
import random
import string
from sqlalchemy import create_engine

app = Flask(__name__)
app.config['MAIL_SERVER'] = 'smtp.gmail.com'
app.config['MAIL_PORT'] = 587
app.config['MAIL_USE_TLS'] = True
app.config['MAIL_USERNAME'] = "your-email@example.com"
app.config['MAIL_PASSWORD'] = "your-password"
mail = Mail(app)

db_uri = "postgresql://username:password@localhost/dbname"
engine = create_engine(db_uri)

def generate_token():
    return ''.join(random.choice(string.ascii_letters + string.digits) for _ in range(32))

@app.route('/api/password-reset', methods=['POST'])
def password_reset():
    email = request.json.get('email')
    token = generate_token()
    conn = engine.connect()
    conn.execute("INSERT INTO password_resets (email, token) VALUES (%s, %s)", (email, token))
    conn.close()

    msg = Message('Password Reset', sender="your-email@example.com", recipients=[email])
    msg.html = f'<a href="/api/password-reset/{token}">Click here to reset your password</a>'
    mail.send(msg)

    return jsonify({"message": "Password reset link sent."})

if __name__ == '__main__':
    app.run()